import React, { useState, useEffect } from "react";
import api from "../api/axios";

export default function EventFilters({ onFilter }) {
  const [categories, setCategories] = useState([]);
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("");
  const [city, setCity] = useState("");
  const [dateFrom, setDateFrom] = useState("");

  useEffect(() => {
    api.get("/events/categories/").then(({ data }) => setCategories(data.results ?? data)).catch(() => {});
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    const params = {};
    if (search) params.search = search;
    if (category) params.category = category;
    if (city) params.city = city;
    if (dateFrom) params.date_from = dateFrom;
    onFilter(params);
  };

  const handleReset = () => {
    setSearch("");
    setCategory("");
    setCity("");
    setDateFrom("");
    onFilter({});
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
        <div>
          <label className="block text-xs font-medium text-gray-700 mb-1">Search</label>
          <input
            type="text"
            placeholder="Event name or keyword..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="input"
          />
        </div>
        <div>
          <label className="block text-xs font-medium text-gray-700 mb-1">Category</label>
          <select value={category} onChange={(e) => setCategory(e.target.value)} className="input">
            <option value="">All Categories</option>
            {categories.map((cat) => (
              <option key={cat.id} value={cat.id}>{cat.name}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="block text-xs font-medium text-gray-700 mb-1">City</label>
          <input
            type="text"
            placeholder="e.g. New York"
            value={city}
            onChange={(e) => setCity(e.target.value)}
            className="input"
          />
        </div>
        <div>
          <label className="block text-xs font-medium text-gray-700 mb-1">From Date</label>
          <input
            type="date"
            value={dateFrom}
            onChange={(e) => setDateFrom(e.target.value)}
            className="input"
          />
        </div>
      </div>
      <div className="flex gap-2 mt-3">
        <button type="submit" className="btn-primary text-sm">Search</button>
        <button type="button" onClick={handleReset} className="btn-secondary text-sm">Reset</button>
      </div>
    </form>
  );
}
